    @staticmethod
    async def as_url_param(repo: str | Repository) -> str:
        assert isinstance(repo, (str, Repository))
        if isinstance(repo, Repository):
            return await repo._identity  # type: ignore
        else:
            # we expect exactly one slash in the repo name
            assert len(repo.split("/")) == 2, repo
            # do not quote the slash as this is expected to become part of URL path
            return urllib.parse.quote(repo, safe="/")

    async def add_to_collaborators(
        self, collaborator: str | NamedUser.NamedUser, permission: Opt[str] = NotSet
    ) -> Invitation.Invitation | None:
        """
        :calls: `PUT /repos/{owner}/{repo}/collaborators/{username} <https://docs.github.com/en/rest/collaborators/collaborators#add-a-repository-collaborator>`_
        :param collaborator: string or :class:`NamedUser.NamedUser`
        :param permission: string 'pull', 'push', 'admin', 'maintain', 'triage', or a custom repository role name, if the owning organization has defined any
        :rtype: None
        """
        assert isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser)) or isinstance(
            collaborator, str
        ), collaborator
        assert is_optional(permission, str), permission

        if isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser)):
            collaborator = await collaborator._identity
        else:
            collaborator = urllib.parse.quote(collaborator, safe="")

        if is_defined(permission):
            put_parameters = {"permission": permission}
        else:
            put_parameters = None

        headers, data = await self._requester.requestJsonAndCheck(
            "PUT", f"{await self.url}/collaborators/{collaborator}", input=put_parameters
        )
        # return an invitation object if there's data returned by the API. If data is empty
        # there's a pending invitation for the given user.
        return Invitation.Invitation(self._requester, headers, data, completed=True) if data is not None else None

    async def get_collaborator_permission(self, collaborator: str | NamedUser.NamedUser) -> str:
        """
        :calls: `GET /repos/{owner}/{repo}/collaborators/{username}/permission <https://docs.github.com/en/rest/reference/repos#collaborators>`_
        :param collaborator: string or :class:`NamedUser.NamedUser`
        :rtype: string
        """
        assert isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser)) or isinstance(
            collaborator, str
        ), collaborator
        if isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser)):
            collaborator = await collaborator._identity
        else:
            collaborator = urllib.parse.quote(collaborator, safe="")
        headers, data = await self._requester.requestJsonAndCheck(
            "GET",
            f"{await self.url}/collaborators/{collaborator}/permission",
        )
        return data["permission"]

    async def get_collaborator_role_name(self, collaborator: str | NamedUser.NamedUser) -> str:
        """
        :calls: `GET /repos/{owner}/{repo}/collaborators/{username}/permission <https://docs.github.com/en/rest/reference/repos#collaborators>`_
        :param collaborator: string or :class:`NamedUser.NamedUser`
        :rtype: string
        """
        assert isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser, str)), collaborator
        if isinstance(collaborator, (NamedUser.NamedUser, github.NamedUser.NamedUser)):
            collaborator = await collaborator._identity
        else:
            collaborator = urllib.parse.quote(collaborator)
        _, data = await self._requester.requestJsonAndCheck(
            "GET",
            f"{await self.url}/collaborators/{collaborator}/permission",
        )
        return data["role_name"]

