    async def get_commits(
        self,
        sha: Opt[str] = NotSet,
        path: Opt[str] = NotSet,
        since: Opt[datetime] = NotSet,
        until: Opt[datetime] = NotSet,
        author: Opt[AuthenticatedUser.AuthenticatedUser | NamedUser.NamedUser | str] = NotSet,
    ) -> PaginatedList[Commit.Commit]:
        """
        :calls: `GET /repos/{owner}/{repo}/commits <https://docs.github.com/en/rest/reference/repos#commits>`_
        :param sha: string
        :param path: string
        :param since: datetime
        :param until: datetime
        :param author: string or :class:`NamedUser.NamedUser` or :class:`AuthenticatedUser.AuthenticatedUser`
        :rtype: :class:`PaginatedList` of :class:`Commit.Commit`
        """
        assert is_optional(sha, str), sha
        assert is_optional(path, str), path
        assert is_optional(since, datetime), since
        assert is_optional(until, datetime), until
        assert is_optional(
            author,
            (str, NamedUser.NamedUser, AuthenticatedUser.AuthenticatedUser),
        ), author
        url_parameters: dict[str, Any] = {}
        if is_defined(sha):
            url_parameters["sha"] = sha
        if is_defined(path):
            url_parameters["path"] = path
        if is_defined(since):
            url_parameters["since"] = since.strftime("%Y-%m-%dT%H:%M:%SZ")
        if is_defined(until):
            url_parameters["until"] = until.strftime("%Y-%m-%dT%H:%M:%SZ")
        if is_defined(author):
            if isinstance(
                author,
                (
                    NamedUser.NamedUser,
                    github.NamedUser.NamedUser,
                    AuthenticatedUser.AuthenticatedUser,
                    github.AuthenticatedUser.AuthenticatedUser,
                ),
            ):
                url_parameters["author"] = await author.login
            else:
                url_parameters["author"] = author
        return PaginatedList(Commit.Commit, self._requester, f"{await self.url}/commits", url_parameters)

    async def get_contents(
        self, path: str, ref: Opt[str] = NotSet
    ) -> list[ContentFile.ContentFile] | ContentFile.ContentFile:
        """
        :calls: `GET /repos/{owner}/{repo}/contents/{path} <https://docs.github.com/en/rest/reference/repos#contents>`_
        :param path: string
        :param ref: string
        :rtype: :class:`ContentFile.ContentFile` or a list of them
        """
        assert isinstance(path, str), path
        assert is_optional(ref, str), ref
        # Path of '/' should be the empty string.
        if path == "/":
            path = ""
        url_parameters = dict()
        if is_defined(ref):
            url_parameters["ref"] = ref
        headers, data = await self._requester.requestJsonAndCheck(
            "GET",
            f"{await self.url}/contents/{urllib.parse.quote(path)}",
            parameters=url_parameters,
            follow_302_redirect=True,
        )

        if isinstance(data, list):
            return [
                # Lazy completion only makes sense for files. See discussion
                # here: https://github.com/jacquev6/PyGithub/issues/140#issuecomment-13481130
                ContentFile.ContentFile(self._requester, headers, item, completed=(item["type"] != "file"))
                for item in data
            ]
        return ContentFile.ContentFile(self._requester, headers, data, completed=True)

